    def handle(self, *args, **options):
        updated = 0
        for model_key, desc in self.DESCRIPTIONS.items():
            cars = Car.objects.filter(model=model_key)
            for car in cars:
                full_desc = (
                    f"## Внешний вид и дизайн\n{desc['design']}\n\n"
                    f"## Технические характеристики\n{desc['tech']}\n\n"
                    f"## Оснащение и технологии\n{desc['features']}"
                )
                car.description = full_desc
                car.save()
                updated += 1
            self.stdout.write(f'OK: {model_key} ({cars.count()} шт)')
        
        self.stdout.write(self.style.SUCCESS(f'\nОбновлено {updated} автомобилей'))